+static char *dup_str(const char *s)
+{
+    size_t len = strlen(s);
+    char *copy = (char *)malloc(len + 1u);
+    if (copy != NULL) {
+        memcpy(copy, s, len + 1u);
+    }
+    return copy;
+}
