+/* -------------------------------------------------------------------
+ * Scenario: import with corrupted magic
+ * ------------------------------------------------------------------- */
+
+static void scenario_import_bad_magic(void)
+{
+    uint8_t buf[8192];
+    uint32_t len = 0;
+
+    SCENARIO_BEGIN("continuity.bad_magic");
+
+    asx_runtime_reset();
+    asx_trace_reset();
