+/* -------------------------------------------------------------------
+ * Helpers
+ * ------------------------------------------------------------------- */
+
+static int g_pass = 0;
+static int g_fail = 0;
+
+#define SCENARIO_BEGIN(id) \
+    do { const char *_scenario_id = (id); int _scenario_ok = 1; (void)0
+
+#define SCENARIO_CHECK(cond, msg)                         \
+    do {                                                  \
+        if (!(cond)) {                                    \
+            printf("SCENARIO %s fail %s\n",               \
