+
+    SCENARIO_CHECK(asx_task_get_state(tid, &ts) == ASX_OK &&
+                   ts == ASX_TASK_COMPLETED, "task not COMPLETED");
+
+    SCENARIO_CHECK(asx_task_get_outcome(tid, &out) == ASX_OK &&
+                   out.severity == ASX_OUTCOME_OK, "outcome not OK");
