+/* robust-endian-006: BE u64 round-trip */
+static void scenario_be_u64_roundtrip(void)
+{
+    SCENARIO_BEGIN("robust-endian-006.be_u64_roundtrip");
+
+    uint64_t test_vals[] = {0, 1, 0x00000000000000FFULL, 0xFF00000000000000ULL,
