+    SCENARIO_END();
+}
+
+/* robust-fault-trace-001: trace digest stable under fault hooks */
+static void scenario_trace_digest_stable_under_faults(void)
+{
+    SCENARIO_BEGIN("robust-fault-trace-001.digest_stable");
