+/*
+ * test_cancellation.c — runtime-level cancellation tests (bd-2cw.3)
+ *
+ * Tests cancellation propagation, checkpoint protocol, cleanup budget
+ * enforcement, cancel strengthening at runtime, and region-wide cancel.
