+    ASSERT_EQ(asx_trace_export_binary(g_buf, BUF_SIZE, &out_len), ASX_OK);
+    /* Pass only header + 1 event instead of 2 */
+    ASSERT_EQ(asx_trace_import_binary(g_buf,
