+    /* Both tasks should have completed */
+    ASSERT_EQ(asx_task_get_state(tid1, &s1), ASX_OK);
+    ASSERT_EQ((int)s1, (int)ASX_TASK_COMPLETED);
+    ASSERT_EQ(asx_task_get_state(tid2, &s2), ASX_OK);
