+    ASSERT_EQ(asx_region_open(&rid1), ASX_OK);
+    ASSERT_EQ(asx_region_open(&rid2), ASX_OK);
+
+    ASSERT_EQ(asx_task_spawn(rid1, poll_pending, NULL, &tid1), ASX_OK);
+    ASSERT_EQ(asx_task_spawn(rid2, poll_complete, NULL, &tid2), ASX_OK);
