+
+        /* Compare event streams */
+        for (i = 0; i < event_count_1 && i < 256u; i++) {
+            if (events_1[i].kind != events_2[i].kind ||
+                events_1[i].round != events_2[i].round ||
+                events_1[i].sequence != events_2[i].sequence) {
+                events_match = 0;
+                break;
+            }
+        }
+    }
