+ * ------------------------------------------------------------------- */
+
+TEST(hft_burst_errors_do_not_corrupt_peers)
+{
+    asx_region_id rid = ASX_INVALID_ID;
+    asx_task_id ok_tids[8];
+    asx_task_id fail_tids[8];
+    asx_budget budget;
+    uint32_t i;
+    uint32_t ok_count;
+    uint32_t err_count;
