+    reset_all();
+    ASSERT_EQ(asx_region_open(&rid), ASX_OK);
+
+    /* 8 successful tasks + 8 failing tasks interleaved */
+    for (i = 0; i < 8; i++) {
+        ASSERT_EQ(asx_task_spawn(rid, poll_immediate, NULL, &ok_tids[i]),
+                  ASX_OK);
+        ASSERT_EQ(asx_task_spawn(rid, poll_fail, NULL, &fail_tids[i]),
+                  ASX_OK);
