+    /* At least the first OK task should have OK outcome (before poison) */
+    ASSERT_TRUE(ok_count > 0 || err_count > 0);
+    /* All 8 fail tasks must have non-OK outcome */
+    ASSERT_EQ(err_count, 8u);
