+
+    sc.ntasks = 1;
+    memset(sc.behaviors, 0, sizeof(sc.behaviors));
+    memset(sc.timings, 0, sizeof(sc.timings));
+
+    for (b = 0; b < (int)BEHAV_COUNT; b++) {
